USE smart_glass_dev;

-- sensor_timeseries dummy data for 3 demo cases
-- total rows: 7500 (2500 per case)
-- assumes inspections: 1,2,3 and devices: DEV-MAF-01, DEV-ECU-02, DEV-IGN-03 already exist

START TRANSACTION;

-- Optional cleanup for rerun
DELETE FROM sensor_timeseries WHERE inspection_id IN (1,2,3);
















COMMIT;

-- Quick checks
SELECT device_id, COUNT(*) AS row_count, MIN(timestamp) AS start_time, MAX(timestamp) AS end_time,
        MIN(failure) AS min_failure, MAX(failure) AS max_failure
FROM sensor_timeseries
WHERE inspection_id IN (1,2,3)
GROUP BY device_id;
